const body = $input.first().json.body;
const sessionId = body.session_id || '';
const message   = body.message   || '';

if (!sessionId || !message) {
  throw new Error('session_id and message are required');
}

return [{ json: { session_id: sessionId, message: message } }];

const apiResp = $input.first().json;
const body    = $('Get Session History').first().json;
const loaded  = (apiResp && apiResp.session) || null;

const session = loaded || { history: [], alumno_id: null, estado: 'sin_autenticar', intentos_auth: 0 };

const history       = session.history || [];
const session_state = session.estado || 'sin_autenticar';
const alumno_id     = session.alumno_id || null;

const systemPrompt = `Sos Ianna, la asistente virtual del Instituto AMICANA (Instituto Cultural Argentino Norteamericano). Atendes a alumnos y a personas interesadas en los cursos. Dirigite SIEMPRE a la persona de manera formal y cordial, tratandola de usted; manten las respuestas breves, claras y profesionales.

Responde SIEMPRE con un JSON valido con exactamente estas claves: intent, params, response.

INTENTS DISPONIBLES:
AUTH: la persona quiere identificarse, o pide informacion personal (cuotas, deuda, pagos) sin estar autenticada. Si menciona un numero de documento ponelo en params.dni; si menciona un correo ponelo en params.email.
ESTADO: ya autenticada, quiere ver sus cuotas, deuda o estado de cuenta.
PAGAR: quiere pagar o abonar una cuota. Si indica cual, pone el numero en params.cuota_id.
CONFIRMAR: informa que ya realizo un pago. Si los menciona, pone params.cuota_id y params.comprobante.
CERRAR: se despide o da por terminada la conversacion.
FUERA_SCOPE: cualquier otra consulta (saludo, horarios, cursos, modalidades, examenes, inscripciones o dudas generales). Responde de forma util y formal en el campo response, usando SOLO esta informacion real:
  - Horarios: lunes a viernes de 8:30 a 21:00; sabados de 8:30 a 12:30.
  - Modalidades: presencial, virtual e hibrida.
  - Cursos: English A1 Beginners, B1 Intermediate, C1 Advanced y Conversation Class.
  - Examenes internacionales: ECECE (nivel A2), TOEIC Bridge (A2), TOEIC (B1) y TOEFL iBT (B2).
  - Inscripciones: de forma presencial en la sede o por este mismo chat.
  - Para consultar cuotas o pagar es necesario identificarse con documento o correo.

REGLAS DE CONVERSACION (muy importantes):
- Aprovecha el historial: NO vuelvas a preguntar ni a repetir informacion ya intercambiada, y si ya saludaste no te presentes de nuevo.
- Al iniciar la conversacion la persona ya vio un saludo con un menu de opciones (consultar cuotas, pagar una cuota, informacion de cursos y examenes). Si elige una opcion (un numero, o frases como 'mis cuotas', 'pagar', 'cursos', 'examenes'), interpreta su intencion y avanza; nunca vuelvas a mostrar el menu completo.
- Si no entendes, pedi una aclaracion concreta y DISTINTA de la anterior; jamas repitas la misma frase dos veces seguidas.
- Si no esta autenticada y pide ESTADO, PAGAR o CONFIRMAR, usa AUTH y pedi documento o correo una sola vez por turno.
- No inventes datos que no figuren arriba; si no tenes el dato, indica que puede consultarlo en secretaria o en la sede.
- El campo response va siempre en espanol formal (trato de usted), en 1 a 3 oraciones.

Estado de la sesion: ${session_state}
Alumno identificado: ${alumno_id || 'ninguno'}`;

const messages = [{ role: 'system', content: systemPrompt }]
  .concat(history.map(h => ({ role: h.role === 'model' ? 'assistant' : 'user', content: (h.parts && h.parts[0] ? h.parts[0].text : '') })))
  .concat([{ role: 'user', content: body.message }]);

return [{
  json: {
    session_id: body.session_id,
    message: body.message,
    history: history,
    alumno_id: alumno_id,
    session_state: session_state,
    intentos_auth: session.intentos_auth || 0,
    messages: messages
  }
}];

const resp = $input.first().json;
const cand = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
let parsed;
if (!cand) {
  const apiErr = (resp.error && resp.error.message) ? resp.error.message : JSON.stringify(resp).slice(0, 300);
  parsed = { intent: 'FUERA_SCOPE', params: {}, response: '[DIAG] Groq no respondio: ' + apiErr };
} else {
  try {
    const clean = cand.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (err) {
    parsed = { intent: 'FUERA_SCOPE', params: {}, response: 'Disculpe, no pude procesar su consulta. ¿Podría reformularla, por favor?' };
  }
}

const prev = $('Hydrate Session').first().json;
return [{
  json: {
    intent: (parsed.intent || 'FUERA_SCOPE').toUpperCase(),
    params: parsed.params || {},
    response: parsed.response || '',
    session_id: prev.session_id,
    message: prev.message,
    history: prev.history,
    alumno_id: prev.alumno_id,
    session_state: prev.session_state,
    intentos_auth: prev.intentos_auth
  }
}];

const apiResult = $input.first().json;
const prev = $('Parse Intent').first().json;
const session = { history: prev.history || [], alumno_id: prev.alumno_id, estado: prev.session_state || 'sin_autenticar', intentos_auth: prev.intentos_auth || 0 };

let text;

if (apiResult.ok && apiResult.alumno) {
  const a = apiResult.alumno;
  text = `¡Hola, ${a.nombre}! Te identifiqué correctamente. Podés consultar tus cuotas, pagar una cuota o confirmar un pago ya realizado.`;
  session.estado = 'autenticado';
  session.alumno_id = a.id;
  session.intentos_auth = 0;
} else {
  session.intentos_auth = (session.intentos_auth || 0) + 1;
  if (session.intentos_auth >= 3) {
    text = 'No pude identificarte luego de 3 intentos. Comunicate con la secretaria de AMICANA. ¡Hasta luego!';
    session.estado = 'cerrado';
  } else {
    text = `No encontré ningún alumno con esos datos (intento ${session.intentos_auth}/3). ¿Podés verificar tu DNI o email e intentar de nuevo?`;
  }
}

const updated = (prev.history || []).concat(
  { role: 'user',  parts: [{ text: prev.message }] },
  { role: 'model', parts: [{ text: text }] }
);
const MAX_TURNS = 10;
session.history = updated.slice(-MAX_TURNS * 2);

return [{ json: { text, qr_url: null, pdf_url: null, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: session.alumno_id, estado: session.estado, intentos_auth: session.intentos_auth, history: session.history } } }];

const apiResult = $input.first().json;
const prev = $('Parse Intent').first().json;
const session = { history: prev.history || [], alumno_id: prev.alumno_id, estado: prev.session_state || 'autenticado', intentos_auth: prev.intentos_auth || 0 };

let text;
if (!prev.alumno_id) {
  text = 'Primero necesito identificarte. ¿Cuál es tu DNI o email?';
} else if (apiResult.ok) {
  const r = apiResult.resumen;
  if (r.estado === 'Al día') {
    text = `¡Estás al día! Tenés ${r.cuotas_pagadas} cuota(s) paga(s). No hay deuda pendiente.`;
  } else {
    const lista = (apiResult.pendientes || []).map(c => `• ${c.concepto}: $${c.monto} (vence ${c.fecha_vencimiento})`).join('\n');
    text = `Tenés deuda por $${r.deuda_total}. Cuotas pendientes:\n${lista}\n\n¿Querés pagar alguna? Decime el número de cuota.`;
  }
} else {
  text = 'No pude obtener tu estado de cuenta. Intentá de nuevo en unos segundos.';
}

const updated = (prev.history || []).concat(
  { role: 'user',  parts: [{ text: prev.message }] },
  { role: 'model', parts: [{ text: text }] }
);
const MAX_TURNS = 10;
session.history = updated.slice(-MAX_TURNS * 2);

return [{ json: { text, qr_url: null, pdf_url: null, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: session.alumno_id, estado: session.estado, intentos_auth: session.intentos_auth, history: session.history } } }];

const pdfResult = $('Pagar — Generar PDF').first().json;
const mpResult  = $('Pagar — Crear Pago MP').first().json;
const prev = $('Parse Intent').first().json;
const session = { history: prev.history || [], alumno_id: prev.alumno_id, estado: prev.session_state || 'autenticado', intentos_auth: prev.intentos_auth || 0 };

let text, qr_url = null, pdf_url = null;

if (!prev.alumno_id) {
  text = 'Primero necesito identificarte. ¿Cuál es tu DNI o email?';
} else if (!prev.params?.cuota_id) {
  text = 'Para generar el pago necesito saber qué cuota querés abonar. ¿Podés decirme el número de cuota?';
} else if (mpResult.ok) {
  const link = mpResult.sandbox_init_point || mpResult.init_point || null;
  const monto = mpResult.monto || '';
  text = monto ? `Generé el enlace de pago por $${monto}.` : 'Generé el enlace de pago.';
  if (link) text += ` Pagá con MercadoPago: ${link}`;
  if (pdfResult.ok && pdfResult.pdf_url) {
    pdf_url = pdfResult.pdf_url;
    text += ' También podés descargar tu comprobante en PDF.';
  }
} else {
  text = 'No pude generar el pago en este momento. Intentá de nuevo o contactá a secretaría.';
}

const updated = (prev.history || []).concat(
  { role: 'user',  parts: [{ text: prev.message }] },
  { role: 'model', parts: [{ text: text }] }
);
const MAX_TURNS = 10;
session.history = updated.slice(-MAX_TURNS * 2);

return [{ json: { text, qr_url, pdf_url, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: session.alumno_id, estado: session.estado, intentos_auth: session.intentos_auth, history: session.history } } }];

const apiResult = $input.first().json;
const prev = $('Parse Intent').first().json;
const session = { history: prev.history || [], alumno_id: prev.alumno_id, estado: prev.session_state || 'autenticado', intentos_auth: prev.intentos_auth || 0 };

let text;
if (!prev.alumno_id) {
  text = 'Primero necesito identificarte. ¿Cuál es tu DNI o email?';
} else if (apiResult.ok) {
  text = apiResult.mensaje || 'Tu confirmación de pago fue registrada. Un administrador la validará pronto.';
} else {
  text = `No pude registrar la confirmación: ${apiResult.detail || 'error desconocido'}. Revisá los datos e intentá de nuevo.`;
}

const updated = (prev.history || []).concat(
  { role: 'user',  parts: [{ text: prev.message }] },
  { role: 'model', parts: [{ text: text }] }
);
const MAX_TURNS = 10;
session.history = updated.slice(-MAX_TURNS * 2);

return [{ json: { text, qr_url: null, pdf_url: null, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: session.alumno_id, estado: session.estado, intentos_auth: session.intentos_auth, history: session.history } } }];

const prev = $('Parse Intent').first().json;
const text = prev.response || '¡Hasta luego! Si necesitás ayuda de nuevo, estoy por acá.';
// Cerrar marca la sesión y deja el history como estaba (sin agregar más turnos).
return [{ json: { text, qr_url: null, pdf_url: null, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: prev.alumno_id, estado: 'cerrado', intentos_auth: prev.intentos_auth || 0, history: prev.history || [] } } }];

const prev = $('Parse Intent').first().json;
const session = { history: prev.history || [], alumno_id: prev.alumno_id, estado: prev.session_state || 'sin_autenticar', intentos_auth: prev.intentos_auth || 0 };

const text = prev.response || 'Puedo ayudarle con sus cuotas y pagos, y con información sobre cursos, modalidades y exámenes internacionales. ¿Sobre qué tema desea consultar?';

const updated = (prev.history || []).concat(
  { role: 'user',  parts: [{ text: prev.message }] },
  { role: 'model', parts: [{ text: text }] }
);
const MAX_TURNS = 10;
session.history = updated.slice(-MAX_TURNS * 2);

return [{ json: { text, qr_url: null, pdf_url: null, session_id: prev.session_id, _session: { session_id: prev.session_id, alumno_id: session.alumno_id, estado: session.estado, intentos_auth: session.intentos_auth, history: session.history } } }];

const data = $input.first().json;
const sessionData = data._session;

if (sessionData) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'https://proyecto-amicana-20-production.up.railway.app/chatbot/session',
      headers: {
        'Content-Type': 'application/json',
        'X-Chatbot-Key': $env.CHATBOT_INTERNAL_KEY || 'amicana-internal'
      },
      body: sessionData,
      timeout: 8000
    });
  } catch(e) {
    // non-fatal
  }
}

return [{ json: {
  text: data.text || 'Lo siento, ocurrió un error.',
  qr_url: data.qr_url || null,
  pdf_url: data.pdf_url || null
} }];
